textarea{min-height:120px;resize:vertical}
button[type="submit"]{width:100%;padding:12px;background:linear-gradient(135deg,#667eea,#764ba2);color:#fff;border:none;border-radius:12px;font-size:1em;font-weight:bold;cursor:pointer;transition:all 0.3s}
button[type="submit"]:hover{transform:translateY(-2px);box-shadow:0 5px 20px rgba(102,126,234,0.3)}
.result{background:#0d1117;border:1px solid rgba(255,255,255,0.1);border-radius:12px;padding:20px;margin-top:15px;white-space:pre-wrap;line-height:1.6;display:none}
.loading{text-align:center;padding:20px;display:none}
.loading::after{content:'Generating...';color:#667eea;font-size:1.1em}
.footer{text-align:center;padding:15px;color:#666;font-size:0.8em;margin-top:10px}
.footer a{color:#667eea;text-decoration:none}
</style>
</head><body>
<div class="container">
<a href="https://crazeemedia.app.n8n.cloud/webhook/ai-tools" class="back-link">&larr; Back to AI Tools Hub</a>
<div class="header"><h1>&#128101; LinkedIn Post Generator</h1><p>Create engaging LinkedIn posts with AI</p></div>

<div style="background:linear-gradient(135deg,#f093fb 0%,#f5576c 50%,#ff9a56 100%);border-radius:14px;padding:18px 22px;margin:20px 0;position:relative;overflow:hidden">
<div style="display:flex;align-items:center;justify-content:space-between;flex-wrap:wrap;gap:10px;position:relative;z-index:1">
<div>
<strong style="color:#fff;font-size:1.05em">&#11088; Get the n8n AI Templates Bundle</strong>
<p style="color:rgba(255,255,255,0.9);font-size:0.85em;margin-top:3px">Production-ready workflows including this tool and more - $4.99</p>
</div>
<a href="https://payhip.com/b/sCTo9" target="_blank" style="background:rgba(255,255,255,0.95);color:#e0457b;padding:8px 20px;border-radius:20px;text-decoration:none;font-weight:bold;font-size:0.9em;white-space:nowrap">Get Templates</a>
</div>
</div>

<div class="form-card">
<form id="linkedinForm" onsubmit="generate(event)">
<label>Post Tone</label>
<select name="tone" id="tone">
<option value="professional">Professional</option>
<option value="thought-leader">Thought Leader</option>
<option value="storytelling">Storytelling</option>
<option value="inspirational">Inspirational</option>
<option value="educational">Educational</option>
</select>
<label>Post Length</label>
<select name="length" id="length">
<option value="short">Short (1-3 sentences)</option>
<option value="medium">Medium (1 paragraph)</option>
<option value="long">Long (multiple paragraphs)</option>
</select>
<label>Topic / What should the post be about?</label>
<textarea name="topic" id="topic" placeholder="E.g., Lessons I learned from failing my first startup..." required></textarea>
<button type="submit">Generate Post</button>
</form>
<div class="loading" id="loading"></div>
<div class="result" id="result"></div>
</div>

<div style="text-align:center;padding:18px;background:linear-gradient(145deg,#1a1a2e,#16213e);border:1px solid rgba(255,255,255,0.1);border-radius:14px;margin-top:20px">
<p style="color:#aaa;font-size:0.85em;margin-bottom:8px">&#9829; Like this tool? Check out our premium templates and resources</p>
<a href="https://payhip.com/ArmanisDevTools" target="_blank" style="color:#667eea;text-decoration:none;font-weight:bold;font-size:0.9em">Visit Our Store</a>
<span style="color:#444;margin:0 8px">|</span>
<a href="https://crazeemedia.app.n8n.cloud/webhook/ai-tools" style="color:#667eea;text-decoration:none;font-size:0.9em">All Tools</a>
<span style="color:#444;margin:0 8px">|</span>
<a href="https://ko-fi.com/armanidev" target="_blank" style="color:#667eea;text-decoration:none;font-size:0.9em">Support on Ko-fi</a>
</div>

<div class="footer"><p>Built by <a href="https://github.com/acunningham-ship-it">Armani</a> | <a href="https://payhip.com/ArmanisDevTools">Shop Templates</a></p></div>
</div>
<script>
async function generate(e) {
  e.preventDefault();
  const loading = document.getElementById('loading');
  const result = document.getElementById('result');
  loading.style.display = 'block';
  result.style.display = 'none';
  try {
    const resp = await fetch('https://crazeemedia.app.n8n.cloud/webhook/linkedin-api', {
      method: 'POST',
      headers: {'Content-Type': 'application/json'},
      body: JSON.stringify({
        tone: document.getElementById('tone').value,
        length: document.getElementById('length').value,
        topic: document.getElementById('topic').value
      })
    });
    const data = await resp.json();
    result.textContent = data.post || data.text || data.output || JSON.stringify(data);
    result.style.display = 'block';
  } catch(err) {
    result.textContent = 'Error: ' + err.message;
    result.style.display = 'block';
  }
  loading.style.display = 'none';
}
</script>
</body></html>

